#include <iostream>
#include <vector>

using namespace std;

/**
 * @brief Класс для обработки вектора целых чисел
 * @details Предоставляет функциональность для вставки элементов в вектор
 *          с использованием итераторов. Основная операция - вставка числа -1
 *          после каждого элемента исходного вектора.
 */
class VectorProcessor {
private:
    vector<int> V; /**< Приватное поле - вектор целых чисел для хранения данных */
    
public:
    /**
     * @brief Конструктор класса VectorProcessor
     * @param vec Исходный вектор целых чисел (передается по константной ссылке)
     * @details Инициализирует внутренний вектор V копией переданного вектора.
     *          Использует список инициализации для эффективного копирования.
     */
    VectorProcessor(const vector<int>& vec) : V(vec) {
        // Тело конструктора пусто, так как вся работа выполнена в списке инициализации
    }
    
    /**
     * @brief Вставляет число -1 после каждого элемента вектора
     * @details Использует итератор для перебора элементов вектора.
     *          1. Итератор i указывает на текущий элемент
     *          2. Вставка -1 выполняется в позицию i+1 (после текущего элемента)
     *          3. Функция insert возвращает итератор на вставленный элемент
     *          4. Сохраняем возвращенный итератор, чтобы он оставался корректным
     *          5. Увеличиваем итератор на 1, чтобы перейти к следующему исходному элементу
     *          Важно: После каждой вставки старые итераторы становятся недействительными,
     *          поэтому  присваиваиваем i результат функции insert.
     * 
     * @warning сохраняем результат insert, иначе итератор станет недействительным
     */
    void insertAfterEach() {
        // Получаем итератор на первый элемент вектора
        auto i = V.begin();
        
        // Цикл продолжается, пока не дойдем до конца вектора
        while (i != V.end()) {
            /**
             * Вставляем -1 после текущего элемента
             * i + 1 - позиция для вставки (после элемента, на который указывает i)
             * insert возвращает итератор на вставленный элемент
             * Сохраняем возвращенный итератор в i
             */
            i = V.insert(i + 1, -1);
            
            /**
             * Переходим к следующему исходному элементу
             * После вставки i указывает на -1
             * Увеличиваем i на 1, чтобы перейти к следующему исходному элементу
             */
            ++i;
        }
    }
    
    /**
     * @brief Выводит содержимое вектора на экран
     * @details Использует цикл for-each для перебора всех элементов
     *          и выводит их через пробел в одной строке.
     * 
     * @note Метод объявлен как const, так как не изменяет состояние объекта
     */
    void display() const {
        cout << "Вектор: ";
        
        // Цикл for-each для вывода всех элементов
        for (int value : V) {
            cout << value << " ";
        }
        cout << endl;
    }
    
    /**
     * @brief Возвращает копию внутреннего вектора
     * @return vector<int> Копия вектора V
     * @details Метод-геттер для доступа к данным класса.
     *          Возвращает копию, чтобы защитить исходные данные от изменения.
     * 
     * @note Метод объявлен как const, так как не изменяет состояние объекта
     */
    vector<int> getVector() const {
        return V;  // Возвращаем копию вектора
    }
    
    /**
     * @brief устанавливаем новый вектор
     * @param vec Новый вектор для хранения (передается по константной ссылке)
     * @details Метод-сеттер для изменения данных класса.
     *          Заменяет текущий вектор V на переданный.
     */
    void setVector(const vector<int>& vec) {
        V = vec;  // Копируем новый вектор
    }
    
    /**
     * @brief Получает размер вектора
     * @return size_t Количество элементов в векторе
     * @details Возвращает текущий размер вектора.
     */
    size_t getSize() const {
        return V.size();
    }
    
    /**
     * @brief Очищает вектор
     * @details Удаляет все элементы из вектора, делая его пустым.
     */
    void clear() {
        V.clear();
    }
    
    /**
     * @brief Проверяет, пуст ли вектор
     * @return true если вектор пуст, false в противном случае
     */
    bool isEmpty() const {
        return V.empty();
    }
};

/**
 * @brief Главная функция 
 * @return int Код возврата (0 - успешное выполнение)
 * @details работа класса VectorProcessor:
 *          1. Создает исходный вектор с числами от 1 до 5
 *          2. Выводит исходный вектор
 *          3. Создает объект класса VectorProcessor
 *          4. Выполняет вставку -1 после каждого элемента
 *          5. Выводит результат
 *          6. Отображает дополнительную информацию о выполненной операции
 */
int main() {
    /**
     * @brief Исходный вектор для демонстрации
     */
    vector<int> original = {1, 2, 3, 4, 5};
    
    // Выводим исходный вектор
    cout << "========================================" << endl;
    cout << "    Демонстрация работы программы" << endl;
    cout << "========================================" << endl;
    cout << "\nИсходный вектор: ";
    for (int val : original) {
        cout << val << " ";
    }
    cout << endl;
    
    /**
     * @brief Создание объекта для обработки вектора
     */
    VectorProcessor processor(original);
    
    // операция вставки
    cout << "\nвставка -1 после каждого элемента..." << endl;
    processor.insertAfterEach();
    
    // Выводим результат
    cout << "\nРезультат: ";
    processor.display();
    
    // Дополнительная информация
    cout << "\nчто выдает операция" << endl;
    cout << "Исходный размер вектора: " << original.size() << endl;
    cout << "Результирующий размер: " << processor.getSize() << endl;
    cout << "Количество вставок: " << original.size() << endl;
    cout << "Количество элементов -1: " << original.size() << endl;
    
    // Демонстрация работы дополнительных методов
    cout << "Вектор пуст? " << (processor.isEmpty() ? "Да" : "Нет") << endl;
    
    // Создаем новый вектор
    vector<int> newVector = {10, 20, 30};
    cout << "\nУстанавливаем новый вектор: ";
    for (int val : newVector) {
        cout << val << " ";
    }
    cout << endl;
    
    processor.setVector(newVector);
    cout << "Новый вектор после вставки -1: ";
    processor.insertAfterEach();
    processor.display();
    
    // Очищаем вектор
    processor.clear();
    cout << "\nПосле очистки вектор пуст? " << (processor.isEmpty() ? "Да" : "Нет") << endl;
    
    cout << "Программа  завершена" << endl;
    
    return 0;
}